#!/usr/bin/env node
// Generates src/build-info.ts at build time with commit hash, dirty flag,
// version, and build timestamp. This keeps execSync out of the runtime plugin
// code entirely, which is important for security scanners (ClawHub, npm audit)
// that flag child_process usage in runtime code.
//
// Wired as part of `prebuild` in package.json so it runs before every tsc
// compilation. The generated file is gitignored — treat it as a build artifact.

import { readFileSync, writeFileSync, mkdirSync } from "node:fs";
import { resolve, dirname } from "node:path";
import { fileURLToPath } from "node:url";
import { execSync } from "node:child_process";

const root = resolve(dirname(fileURLToPath(import.meta.url)), "..");

// Version from package.json (single source of truth).
const pkg = JSON.parse(readFileSync(resolve(root, "package.json"), "utf8"));
const version = pkg.version ?? "unknown";

// Git commit info — best effort; falls back gracefully when git is unavailable.
let commit = "unknown";
let dirty = false;
try {
  commit = execSync("git rev-parse --short HEAD", {
    cwd: root,
    stdio: ["ignore", "pipe", "ignore"],
  }).toString().trim();
  const status = execSync("git status --porcelain", {
    cwd: root,
    stdio: ["ignore", "pipe", "ignore"],
  }).toString();
  dirty = status.trim().length > 0;
} catch {
  // Not a git repo or git not available — leave defaults.
}

const builtAt = new Date().toISOString();

const lines = [
  "// AUTO-GENERATED by scripts/gen-build-info.mjs — do not edit manually.",
  "// Regenerated on every `npm run build` (via prebuild hook).",
  "// This file is gitignored; commit info is baked in at build time.",
  `export const BUILD_VERSION = ${JSON.stringify(version)};`,
  `export const BUILD_COMMIT = ${JSON.stringify(commit)};`,
  `export const BUILD_DIRTY = ${dirty};`,
  `export const BUILD_AT = ${JSON.stringify(builtAt)};`,
  "",
];

const srcDir = resolve(root, "src");
mkdirSync(srcDir, { recursive: true });
writeFileSync(resolve(srcDir, "build-info.ts"), lines.join("\n"));
console.log(`[gen-build-info] src/build-info.ts generated (v${version} @ ${commit}${dirty ? " dirty" : ""})`);
